INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (38, '50', 'Çalıştığı ekipmanları özenli ve titiz kullanır. Temizliğini yapar.');
INSERT INTO position_categories (id, positionId, name) VALUES (39, 1, 'Görev Bilinci');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (39, '1', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
