INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (39, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (39, '4', 'Ahlaki ve etik değerlere uygun davranır.');
INSERT INTO position_categories (id, positionId, name) VALUES (40, 1, 'İletişim Becerisi');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (40, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (40, '6', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (40, '7', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (40, '8', 'Her türlü iletişimde empati kurmaya özen gösterir.');
INSERT INTO position_categories (id, positionId, name) VALUES (41, 1, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (41, '9', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (41, '10', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (41, '11', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (41, '12', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (42, 1, 'Kalite Odaklılık');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (42, '13', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
