INSERT INTO position_categories (id, positionId, name) VALUES (44, 1, 'Müşteri Odaklılık');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (44, '21', 'Müşteri ihtiyaçlarını anlar ve bu ihtiyaçları doğru şekilde tanımlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (44, '22', 'Müşteri sorunlarına hızlı ve etkili çözümler bulur.');
