INSERT INTO position_categories (id, positionId, name) VALUES (47, 1, 'İş Disiplini ve Tutum');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (47, '31', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (47, '32', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
