INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (47, '35', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (48, 1, 'Servis ');
