INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (48, '40', 'Ürünlerle ve içerikleri ile ilgili bilgilidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (48, '41', 'Operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (48, '42', 'Menü fiyatları ve pormosyonlarla ilgili bilgilidir.');
