INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (48, '46', 'Restoran düzenini sağlar, dağınık ve kirli bir görüntü verilmesine izin vermez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (48, '47', 'Zor müşteriler ile iletişim kurabilir, gerekli yönlendirmeleri yapar.');
